import type { SampleGroupSpec } from "./specs.js";

/**
 * Templates for the per-project scaffolding the adapter writes alongside the
 * materialized `programs/` tree. Modeled on `examples/aleo-ports/dynamic_dispatch`:
 * the four built-in plugins, Leo 4.2.0, a devnode default network with
 * `autoBlock`, and a generous test timeout.
 *
 * Generated projects live under `generated/<name>/` (gitignored) and resolve
 * `@lionden/*` + `vitest` from the repo-root `node_modules` (module resolution
 * walks up), so they need no per-project `npm install`.
 */

const LEO_VERSION = "4.2.0";
const DEFAULT_TIMEOUT = 240_000;

function renderExecutionImports(spec: SampleGroupSpec): string {
  if (!spec.executionImports || Object.keys(spec.executionImports).length === 0) {
    return "";
  }
  const entries = Object.entries(spec.executionImports)
    .map(([program, targets]) => {
      const list = targets.map((t) => JSON.stringify(t)).join(", ");
      return `      ${JSON.stringify(program)}: [${list}],`;
    })
    .join("\n");
  return `  execution: {\n    imports: {\n${entries}\n    },\n  },\n`;
}

export function renderConfig(spec: SampleGroupSpec): string {
  const timeout = spec.timeout ?? DEFAULT_TIMEOUT;
  return `// GENERATED by test/fixtures/leo-samples/adapter — do not edit by hand.
// Source: leo-samples "${spec.name}" group (.upstream submodule).
import { defineConfig } from "@lionden/config";
import pluginDeploy from "@lionden/plugin-deploy";
import pluginLeo from "@lionden/plugin-leo";
import pluginNetwork from "@lionden/plugin-network";
import pluginTest from "@lionden/plugin-test";

export default defineConfig({
  plugins: [pluginLeo, pluginNetwork, pluginDeploy, pluginTest],
  leoVersion: ${JSON.stringify(LEO_VERSION)},
  defaultNetwork: "devnode",
  networks: {
    devnode: { type: "devnode", autoBlock: true },
  },
  testing: { timeout: ${timeout} },
${renderExecutionImports(spec)}});
`;
}

export function renderPackageJson(spec: SampleGroupSpec): string {
  const pkg = {
    name: `leo-samples-${spec.name.replace(/_/g, "-")}`,
    version: "0.0.0",
    private: true,
    type: "module",
    scripts: {
      compile: "lionden compile",
      test: "lionden test",
    },
    engines: { node: "^20.19.0 || >=22.12.0" },
  };
  return `${JSON.stringify(pkg, null, 2)}\n`;
}

export function renderTsconfig(): string {
  const tsconfig = {
    compilerOptions: {
      target: "ES2024",
      module: "NodeNext",
      moduleResolution: "NodeNext",
      verbatimModuleSyntax: true,
      strict: true,
      skipLibCheck: true,
      noEmit: true,
    },
    include: ["typechain/**/*.ts", "test/**/*.ts", "lionden.config.ts"],
  };
  return `${JSON.stringify(tsconfig, null, 2)}\n`;
}
